/* Optimize your custom font loading for better UX */
@font-face {
  font-family: 'MyCustomFont';
  src: url('/fonts/MyCustomFont-Regular.woff2') format('woff2'),
       url('/fonts/MyCustomFont-Regular.woff') format('woff');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* Crucial for preventing FOIT and improving perceived performance */
}

body {
  font-family: 'MyCustomFont', sans-serif; /* Always provide a robust fallback! */
  font-size: 1.125rem;
  line-height: 1.6;
}

@font-face {
  font-family: 'Inter';
  src: url('/fonts/Inter-Regular.woff2') format('woff2'),
       url('/fonts/Inter-Regular.woff') format('woff');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* Crucial for better UX with web fonts */
}

body {
  font-family: 'Inter', sans-serif;
  line-height: 1.6;
  color: #333;
}

@font-face {
  font-family: 'Custom Brand Font';
  src: url('/fonts/CustomBrandFont-Regular.woff2') format('woff2'),
       url('/fonts/CustomBrandFont-Regular.woff') format('woff');
  font-weight: 400;
  font-style: normal;
  /* 'optional' for critical UI elements, avoids FOUT/FOIT and layout shift */
  font-display: optional; 
}

@font-face {
  font-family: 'Body Text Font';
  src: url('/fonts/BodyTextFont-Regular.woff2') format('woff2'),
       url('/fonts/BodyTextFont-Regular.woff') format('woff');
  font-weight: 400;
  font-style: normal;
  /* 'swap' is generally good for body text to prioritize readability */
  font-display: swap;
}

body {
  font-family: 'Body Text Font', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol';
  font-size: 1.125rem;
  line-height: 1.6;
  color: #222;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

h1 {
  font-family: 'Custom Brand Font', system-ui, sans-serif;
  font-size: 3rem;
  font-weight: 700;
  line-height: 1.1;
  letter-spacing: -0.03em;
}

@font-face {
  font-family: 'Inter V';
  src: url('/fonts/Inter-V.woff2') format('woff2');
  font-weight: 100 900;
  font-style: normal;
  font-display: swap; /* Recommended for body text to prioritize content */
}

@font-face {
  font-family: 'Brand Display';
  src: url('/fonts/BrandDisplay-Bold.woff2') format('woff2');
  font-weight: 700;
  font-style: normal;
  font-display: fallback; /* Short block period, then swap. Good for prominent titles. */
}

/* Example for a less critical, decorative font */
@font-face {
  font-family: 'Decorative Script';
  src: url('/fonts/DecorativeScript.woff2') format('woff2');
  font-weight: 400;
  font-style: normal;
  font-display: optional; /* Font is only loaded if connection is good and cached. */
}

