@font-face {
    font-family: 'Inter Variable';
    src: url('/fonts/Inter-Variable.woff2') format('woff2-variations');
    font-weight: 100 900; /* Define min and max weight range */
    font-display: swap;
}

body {
    font-family: 'Inter Variable', sans-serif;
    font-variation-settings: 'wght' 400; /* Default weight */
    line-height: 1.5;
    color: #333;
}

h1 {
    font-size: clamp(2.5rem, 6vw + 1rem, 4.5rem);
    /* Adjust weight and optical size based on viewport */
    font-variation-settings: 'wght' var(--heading-weight, 700), 'opsz' var(--heading-opsz, 24);
    line-height: 1.1;
    letter-spacing: -0.02em;
}

@media (max-width: 768px) {
    h1 {
        --heading-weight: 600; /* Slightly lighter on smaller screens */
        --heading-opsz: 18;    /* Smaller optical size */
    }
}

.highlight {
    /* Example of custom axis control if font supports it */
    font-variation-settings: 'wght' 900, 'slnt' -10; /* Heavy and slightly slanted */
}

/* Implement fluid typography for adaptive text scaling */
body {
  /* min-size, preferred-size (viewport-based), max-size */
  font-size: clamp(1rem, 2vw + 0.5rem, 1.25rem);
  line-height: 1.6;
}

h1 {
  font-size: clamp(2.5rem, 8vw + 1rem, 5rem);
  line-height: 1.1;
  font-weight: 700;
}

/* Ensure optical size consistency across diverse web fonts */
body {
  font-family: 'Inter', sans-serif;
  font-size: 1rem;
  /* Example: Inter's x-height ratio might be ~0.52 */
}

h1 {
  font-family: 'Playfair Display', serif; /* A font with a naturally different x-height */
  font-size: 2.5rem;
  font-size-adjust: 0.52; /* Set to the target x-height ratio (e.g., from your body font) */
  /* This scales Playfair Display's font-size so its x-height visually matches 52% of its computed font-size,
     creating better optical balance with other fonts like Inter, even at different declared font-sizes. */
}
